Here's a clean implementation using `INotifyPropertyChanged` and `IAsyncRelayCommand`:

```csharp
using System.ComponentModel;
using System.Runtime.CompilerServices;
using System.Windows.Input;

public class ProductDetailViewModel : INotifyPropertyChanged
{
    private string _name = string.Empty;
    private decimal _price;
    private bool _isAvailable;

    public ProductDetailViewModel()
    {
        LoadCommand = new AsyncRelayCommand(LoadAsync);
    }

    public string Name
    {
        get => _name;
        set => SetProperty(ref _name, value);
    }

    public decimal Price
    {
        get => _price;
        set => SetProperty(ref _price, value);
    }

    public bool IsAvailable
    {
        get => _isAvailable;
        set => SetProperty(ref _isAvailable, value);
    }

    public IAsyncRelayCommand LoadCommand { get; }

    private async Task LoadAsync()
    {
        // Replace with your actual data service call
        var product = await FetchProductAsync();
        Name = product.Name;
        Price = product.Price;
        IsAvailable = product.IsAvailable;
    }

    private async Task<(string Name, decimal Price, bool IsAvailable)> FetchProductAsync()
    {
        await Task.Delay(500); // simulate network
        return ("Widget", 29.99m, true);
    }

    // ‚îÄ‚îÄ INotifyPropertyChanged plumbing ‚îÄ‚îÄ

    public event PropertyChangedEventHandler? PropertyChanged;

    private bool SetProperty<T>(ref T field, T value, [CallerMemberName] string? name = null)
    {
        if (EqualityComparer<T>.Default.Equals(field, value)) return false;
        field = value;
        PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(name));
        return true;
    }
}
```

`AsyncRelayCommand` comes from the **CommunityToolkit.Mvvm** NuGet package. If you use that toolkit you can simplify further with `[ObservableProperty]` and `[RelayCommand]` source generators ‚Äî but the above shows the mechanics explicitly.

**Key points:**

- `SetProperty` fires `PropertyChanged` only when the value actually changes.
- `LoadCommand` is exposed as `IAsyncRelayCommand`, which disables itself while running (prevents double-taps).
- Bind in XAML: `{Binding Name}`, `{Binding Price, StringFormat='{0:C}'}`, `{Binding LoadCommand}`.
